const now = new Date();
const end = now.toISOString().slice(0, 10);
const startDateObj = new Date(now);
startDateObj.setUTCDate(startDateObj.getUTCDate() - normalizedDays);
const start = startDateObj.toISOString().slice(0, 10);
const slug = company
