  .replace(/[^a-z0-9]+/g, '_')
  .replace(/^_+|_+$/g, '')
  .slice(0, 60) || 'company';
const runId = `${slug}_${end}_${normalizedDays}d_${item.row_number || 0}`;
const secCik = (item.sec_cik || '').toString().replace(/\D/g, '');
const paddedCik = secCik ? secCik.padStart(10, '0') : '';
const shortCik = secCik ? secCik.replace(/^0+/, '') : '';
const rawDomain = (item.company_domain || item.official_domain || profile.domain || '').toString().trim().toLowerCase();
const companyDomain = rawDomain
