    start_date: start,
    end_date: end,
    safe_file_name: slug,
    run_id: runId,
    official_domains: officialDomainsFinal,
    government_domains: governmentDomains,
    thinktank_domains: thinktankDomains,
    security_domains: securityDomains,
    news_domains: newsDomains,
    official_query: officialQuery,
    government_query: governmentQuery,
    thinktank_query: thinktankQuery,
    security_query: securityQuery,
    announcement_query: announcementQuery,
    targeted_news_query: targetedNewsQuery,
    news_query: newsQuery,
